class Solution:
    def sumCounts(self, nums):
        n = len(nums)
        total = 0
        for i in range(n):
            freq = {}
            distinct = 0
            for j in range(i, n):
                v = nums[j]
                if freq.get(v, 0) == 0:
                    distinct += 1
                freq[v] = freq.get(v, 0) + 1
                total += distinct * distinct
        return total

