var sumCounts = function(nums) {
    const n = nums.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        const freq = new Map();
        let distinct = 0;
        for (let j = i; j < n; j++) {
            const v = nums[j];
            const cur = freq.get(v) || 0;
            if (cur === 0) distinct += 1;
            freq.set(v, cur + 1);
            total += distinct * distinct;
        }
    }
    return total;
};
